document.addEventListener('DOMContentLoaded',function(){const form=document.getElementById('form-estadocuenta');if(!form)return;const inputPlantilla=document.getElementById('input-plantilla-ec'),inputHistorico=document.getElementById('input-historico-ec'),inputContrato=document.getElementById('input-contrato-ec'),btnGenerar=document.getElementById('btn-estadocuenta'),alertaDiv=document.getElementById('alerta-estadocuenta'),estadoDiv=document.getElementById('estado-estadocuenta'),resultadosDiv=document.getElementById('resultados-estadocuenta'),metricasDiv=document.getElementById('metricas-estadocuenta');function formatCurrency(e){return new Intl.NumberFormat('es-CO',{style:'currency',currency:'COP',minimumFractionDigits:0}).format(e||0)}function showResults(e){metricasDiv.innerHTML=`<div class="metrica"><div class="metrica-etiqueta">Contrato</div><div class="metrica-valor">${e.contrato}</div></div><div class="metrica"><div class="metrica-etiqueta">Contratista</div><div class="metrica-valor">${e.contratista}</div></div><div class="metrica"><div class="metrica-etiqueta">Transacciones</div><div class="metrica-valor">${e.pagos_encontrados}</div></div><div class="metrica"><div class="metrica-etiqueta">Valor inicial</div><div class="metrica-valor">${formatCurrency(e.valor_contrato)}</div></div><div class="metrica"><div class="metrica-etiqueta">Saldo final</div><div class="metrica-valor">${formatCurrency(e.saldo_final)}</div></div>`,resultadosDiv.style.display='block',estadoDiv.style.display='none'}function enableBtn(){btnGenerar.disabled=!(inputPlantilla.files.length&&inputHistorico.files.length&&inputContrato.value.trim())}inputPlantilla.addEventListener('change',()=>{document.getElementById('lista-plantilla-ec').innerHTML=inputPlantilla.files[0]?`<div style="color:#28a745;font-size:13px;margin-top:10px;font-weight:500;">✓ ${inputPlantilla.files[0].name}</div>`:'',enableBtn()}),inputHistorico.addEventListener('change',()=>{document.getElementById('lista-historico-ec').innerHTML=inputHistorico.files[0]?`<div style="color:#28a745;font-size:13px;margin-top:10px;font-weight:500;">✓ ${inputHistorico.files[0].name}</div>`:'',enableBtn()}),inputContrato.addEventListener('input',enableBtn),form.addEventListener('submit',async function(e){e.preventDefault(),alertaDiv.style.display='none',estadoDiv.style.display='block';try{if(!window.XLSX)throw new Error('SheetJS no disponible');const t=inputPlantilla.files[0],o=inputHistorico.files[0],a=inputContrato.value.trim();if(!t||!o||!a)throw new Error('Faltan archivos');const r=await o.arrayBuffer(),i=XLSX.read(new Uint8Array(r),{type:'array'}),n=XLSX.utils.sheet_to_json(i.Sheets[i.SheetNames[0]]).filter(e=>String(e.Referencia||'').includes(a));if(!n.length)throw new Error(`No encontrado: ${a}`);const l=n[0],s=await t.arrayBuffer(),c=XLSX.read(new Uint8Array(s),{type:'array'}),d=c.Sheets[c.SheetNames[0]];d.D5={v:a,t:'s'},d.D6={v:String(l.Nombre||''),t:'s'},d.D7={v:Number(l['VALOR FINAL DEL CONTRATO'])||0,t:'n'},d.D8={v:String(l['FECHA INICIAL DE CONTRATO']||''),t:'s'},d.H5={v:String(l.Proveedor||''),t:'s'},d.H6={v:String(l['Nº identificación']||''),t:'s'},d.H7={v:String(l['Numero RP']||''),t:'s'},d.H8={v:String(l['FECHA DE TERMINACION FINAL']||''),t:'s'};let m=17,u=Number(l['VALOR FINAL DEL CONTRATO'])||0;n.forEach((e,t)=>{const o=Number(e['Valor Bruto'])||0;u-=o,d[`B${m}`]={v:t+1,t:'n'},d[`C${m}`]={v:String(e['Texto cabecera documento']||''),t:'s'},d[`D${m}`]={v:o,t:'n'},d[`E${m}`]={v:u,t:'n'},d[`F${m}`]={v:String(e['Doc.compensación']||''),t:'s'},d[`G${m}`]={v:String(e['Fecha de pago']||''),t:'s'},d[`H${m}`]={v:String(e['Numero RP']||''),t:'s'},d[`I${m}`]={v:String(e['CDP Externo']||''),t:'s'},d[`J${m}`]={v:String(e['CRP Externo']||''),t:'s'},m++}),XLSX.writeFile(c,`Estado_de_Cuenta_${a}.xlsx`),showResults({contrato:a,contratista:String(l.Nombre||''),pagos_encontrados:n.length,valor_contrato:Number(l['VALOR FINAL DEL CONTRATO'])||0,saldo_final:u})}catch(e){alertaDiv.textContent=`❌ ${e.message}`,alertaDiv.style.display='block',estadoDiv.style.display='none',console.error(e)}}),enableBtn()});
